export type RatingSource =
  | 'imdb' | 'themoviedb' | 'thetvdb'
  | 'tomato-ripe' | 'tomato-rotten'
  | 'popcorn-upright' | 'popcorn-spilled';

export function getRatingIcon(source: string): string | null {
  const s = source.toLowerCase().trim();
  if (icons[s]) return icons[s];
  // Aliases
  if (s.includes('imdb')) return icons['imdb'] ?? null;
  if (s.includes('tmdb') || s.includes('themoviedb')) return icons['themoviedb'] ?? null;
  if (s.includes('tvdb') || s.includes('thetvdb')) return icons['thetvdb'] ?? null;
  if (s.includes('rotten') && s.includes('fresh')) return icons['tomato-ripe'] ?? null;
  if (s.includes('rotten')) return icons['tomato-rotten'] ?? null;
  if (s.includes('audience') && s.includes('up')) return icons['popcorn-upright'] ?? null;
  if (s.includes('audience') && s.includes('down')) return icons['popcorn-spilled'] ?? null;
  return null;
}
